21.         ///  by other Azure SDK client methods.  It's recommended to set it to true for new clients; use default (null)
22.         ///  for backward compatibility reasons, or set it to false to explicitly disable suppression for specific cases.
23.         ///  The default value could change in the future, the flag should be only set to false if suppression for the client
24.         ///  should never be enabled.</param>
25.         public ClientDiagnostics(ClientOptions options, bool? suppressNestedClientActivities = null)
26.                     : this(options.GetType().Namespace!,
27.                     GetResourceProviderNamespace(options.GetType().Assembly),
28.                     options.Diagnostics,
